301→                    {partCount > 0 && <span className={styles.shapeCount}>{partCount}</span>}
302→                  </div>
303→                  <div className={styles.layerActions}>
304→                    <button
305→                      className={styles.layerActionBtn}
306→                      onClick={(e) => handleGenerateAssemblySheet(e, asm.id)}
307→                      aria-label="Generate Assembly Sheet"
308→                      title="Generate Assembly Sheet"
309→                    >
310→                      <SheetIcon />
311→                    </button>
312→                    <button
313→                      className={styles.layerActionBtn}
314→                      onClick={(e) => handleCloneAssembly(e, asm.id)}
