352→        <div className={styles.layerList}>
353→          {renderPartTree(unassignedParts, 0)}
354→        </div>
355→      </div>
356→
357→      {/* Sheets */}
358→      <div className={styles.section}>
359→        <div className={styles.sectionHeaderRow}>
