  1→import { PAPER_PRESETS } from '@/sheets/paper';
  2→import { projectPartToView, getPartExtents } from '../domain/viewProjection';
  3→import { createDimensionFigure } from '@/annotations/dimensions';
  4→
  5→const MARGIN = 15; // mm
  6→const TITLE_HEIGHT = 12; // mm
  7→const VIEW_GAP = 10; // mm
  8→const STROKE_WIDTH = 0.3;
  9→
 10→function projectDimensionPoint(point, view) {
 11→  switch (view) {
 12→    case 'top':
 13→      return { x: point.x, y: point.y };
 14→    case 'front':
 15→      return { x: point.x, y: -(point.z || 0) };
 16→    case 'side':
 17→      return { x: point.y, y: -(point.z || 0) };
 18→    default:
 19→      return { x: point.x, y: point.y };
 20→  }
 21→}
 22→
 23→function getPartsBounds(parts, view, dimensions = []) {
 24→  let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
 25→
 26→  for (const part of parts) {
 27→    if (part.type === 'dimension') continue;
 28→    const { svgX, svgY, svgWidth, svgHeight } = projectPartToView(part, view);
 29→    minX = Math.min(minX, svgX);
 30→    minY = Math.min(minY, svgY);
 31→    maxX = Math.max(maxX, svgX + svgWidth);
 32→    maxY = Math.max(maxY, svgY + svgHeight);
 33→  }
 34→
 35→  // Include dimension figure bounds
 36→  for (const dim of dimensions) {
 37→    const start2D = projectDimensionPoint(dim.startPoint, view);
 38→    const end2D = projectDimensionPoint(dim.endPoint, view);
 39→    const figure = createDimensionFigure({
 40→      id: dim.id,
 41→      startPoint: start2D,
 42→      endPoint: end2D,
 43→      mode: 'aligned',
 44→      offset: dim.offset || 200,
 45→      label: dim.textOverride || undefined,
 46→      source: 'manual',
 47→    });
 48→    if (!figure) continue;
 49→
 50→    const points = [
 51→      figure.lineStart, figure.lineEnd,
 52→      ...figure.extensionLines.flatMap((l) => [l.start, l.end]),
 53→    ];
 54→    for (const p of points) {
 55→      minX = Math.min(minX, p.x);
 56→      minY = Math.min(minY, p.y);
 57→      maxX = Math.max(maxX, p.x);
 58→      maxY = Math.max(maxY, p.y);
 59→    }
 60→  }
 61→
 62→  if (minX === Infinity) return { x: 0, y: 0, width: 0, height: 0 };
 63→  return { x: minX, y: minY, width: maxX - minX, height: maxY - minY };
 64→}
 65→
 66→function renderViewSvg(parts, view, offsetX, offsetY, scale) {
 67→  const lines = [];
 68→
 69→  for (const part of parts) {
 70→    if (part.type === 'dimension') continue;
 71→    const { svgX, svgY, svgWidth, svgHeight } = projectPartToView(part, view);
 72→    const isSubtractive = part.type === 'cutout' || part.type === 'hole';
 73→
 74→    const x = offsetX + svgX * scale;
 75→    const y = offsetY + svgY * scale;
 76→    const w = svgWidth * scale;
 77→    const h = svgHeight * scale;
 78→
 79→    if (part.type === 'hole' && view === 'top') {
 80→      lines.push(
 81→        `<ellipse cx="${x + w / 2}" cy="${y + h / 2}" rx="${w / 2}" ry="${h / 2}" ` +
 82→        `fill="none" stroke="#333" stroke-width="${STROKE_WIDTH}" ${isSubtractive ? 'stroke-dasharray="1 0.8"' : ''}/>`
 83→      );
 84→    } else {
 85→      lines.push(
 86→        `<rect x="${x}" y="${y}" width="${w}" height="${h}" ` +
 87→        `fill="none" stroke="#333" stroke-width="${STROKE_WIDTH}" ${isSubtractive ? 'stroke-dasharray="1 0.8"' : ''}/>`
 88→      );
 89→    }
 90→  }
 91→
 92→  return lines.join('\n');
 93→}
 94→
 95→function renderDimensionsSvg(dimensions, view, offsetX, offsetY, scale) {
 96→  const lines = [];
 97→  const DIM_STROKE = 0.15;
 98→  const FONT_SIZE = 2.5;
 99→  const ARROW_SCALE = 0.08;
100→
101→  for (const dim of dimensions) {
102→    const start2D = projectDimensionPoint(dim.startPoint, view);
103→    const end2D = projectDimensionPoint(dim.endPoint, view);
104→
105→    const figure = createDimensionFigure({
106→      id: dim.id,
107→      startPoint: start2D,
108→      endPoint: end2D,
109→      mode: 'aligned',
110→      offset: dim.offset || 200,
111→      label: dim.textOverride || undefined,
112→      source: 'manual',
113→    });
114→
115→    if (!figure) continue;
116→
117→    // Extension lines
118→    for (const ext of figure.extensionLines) {
119→      const x1 = offsetX + ext.start.x * scale;
120→      const y1 = offsetY + ext.start.y * scale;
121→      const x2 = offsetX + ext.end.x * scale;
122→      const y2 = offsetY + ext.end.y * scale;
123→      lines.push(`<line x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" stroke="#666" stroke-width="${DIM_STROKE}"/>`);
124→    }
125→
126→    // Dimension line
127→    const lx1 = offsetX + figure.lineStart.x * scale;
128→    const ly1 = offsetY + figure.lineStart.y * scale;
129→    const lx2 = offsetX + figure.lineEnd.x * scale;
130→    const ly2 = offsetY + figure.lineEnd.y * scale;
131→    lines.push(`<line x1="${lx1}" y1="${ly1}" x2="${lx2}" y2="${ly2}" stroke="#333" stroke-width="${DIM_STROKE}"/>`);
132→
133→    // Arrowheads
134→    for (const arrow of figure.arrowheads) {
135→      const tipX = offsetX + arrow.tip.x * scale;
136→      const tipY = offsetY + arrow.tip.y * scale;
137→      const leftX = offsetX + arrow.left.x * scale;
138→      const leftY = offsetY + arrow.left.y * scale;
139→      const rightX = offsetX + arrow.right.x * scale;
140→      const rightY = offsetY + arrow.right.y * scale;
141→      lines.push(`<polygon points="${tipX},${tipY} ${leftX},${leftY} ${rightX},${rightY}" fill="#333"/>`);
142→    }
143→
144→    // Text
145→    const tx = offsetX + figure.text.position.x * scale;
146→    const ty = offsetY + figure.text.position.y * scale;
147→    lines.push(
148→      `<text x="${tx}" y="${ty}" text-anchor="middle" dominant-baseline="central" ` +
149→      `transform="rotate(${figure.text.angle} ${tx} ${ty})" ` +
150→      `font-family="sans-serif" font-size="${FONT_SIZE}" fill="#333">${figure.text.value}</text>`
151→    );
152→  }
153→
154→  return lines.join('\n');
155→}
156→
157→export function exportSketchSvg(project) {
158→  const paper = PAPER_PRESETS.A4_LANDSCAPE;
159→  const pageW = paper.width;
160→  const pageH = paper.height;
161→
162→  const renderParts = project.parts.filter((p) => p.type !== 'dimension');
163→  const dimensions = project.parts.filter((p) => p.type === 'dimension');
164→
165→  if (renderParts.length === 0 && dimensions.length === 0) return null;
166→
167→  const views = ['top', 'front', 'side'];
168→  const viewLabels = { top: 'Top View', front: 'Front View', side: 'Side View' };
169→
170→  // Calculate bounds for each view (including dimensions)
171→  const boundsList = views.map((v) => getPartsBounds(renderParts, v, dimensions));
172→
173→  // Available area for 3 views side by side
174→  const availW = pageW - 2 * MARGIN;
175→  const availH = pageH - 2 * MARGIN - TITLE_HEIGHT - VIEW_GAP;
176→
177→  // Each view gets 1/3 of width
178→  const viewSlotW = (availW - 2 * VIEW_GAP) / 3;
179→  const viewSlotH = availH;
180→
181→  // Find uniform scale that fits all views
182→  let scale = Infinity;
183→  for (let i = 0; i < views.length; i++) {
184→    const b = boundsList[i];
185→    if (b.width > 0) scale = Math.min(scale, viewSlotW / b.width);
186→    if (b.height > 0) scale = Math.min(scale, viewSlotH / b.height);
187→  }
188→  if (!isFinite(scale) || scale <= 0) scale = 0.1;
189→
190→  // Build SVG
191→  let svgContent = '';
192→  svgContent += `<rect x="0" y="0" width="${pageW}" height="${pageH}" fill="white"/>\n`;
193→
194→  // Title block
195→  svgContent += `<text x="${pageW / 2}" y="${MARGIN + 6}" text-anchor="middle" font-family="sans-serif" font-size="5" font-weight="bold" fill="#333">${project.name || 'Untitled'}</text>\n`;
196→  svgContent += `<text x="${pageW - MARGIN}" y="${pageH - 4}" text-anchor="end" font-family="sans-serif" font-size="3" fill="#999">${new Date().toLocaleDateString()}</text>\n`;
197→
198→  // Render each view
199→  for (let i = 0; i < views.length; i++) {
200→    const view = views[i];
201→    const b = boundsList[i];
202→    const slotX = MARGIN + i * (viewSlotW + VIEW_GAP);
203→    const slotY = MARGIN + TITLE_HEIGHT + VIEW_GAP;
204→
205→    // Center within slot
206→    const renderedW = b.width * scale;
207→    const renderedH = b.height * scale;
208→    const offsetX = slotX + (viewSlotW - renderedW) / 2 - b.x * scale;
209→    const offsetY = slotY + (viewSlotH - renderedH) / 2 - b.y * scale;
210→
211→    // View label
212→    svgContent += `<text x="${slotX + viewSlotW / 2}" y="${slotY - 2}" text-anchor="middle" font-family="sans-serif" font-size="3.5" fill="#666">${viewLabels[view]}</text>\n`;
213→
214→    // View border
215→    svgContent += `<rect x="${slotX}" y="${slotY}" width="${viewSlotW}" height="${viewSlotH}" fill="none" stroke="#ddd" stroke-width="0.2"/>\n`;
216→
217→    // Parts
218→    svgContent += renderViewSvg(renderParts, view, offsetX, offsetY, scale);
219→
220→    // Dimensions
221→    svgContent += renderDimensionsSvg(dimensions, view, offsetX, offsetY, scale);
222→  }
223→
224→  // Page border
225→  svgContent += `<rect x="0.5" y="0.5" width="${pageW - 1}" height="${pageH - 1}" fill="none" stroke="#999" stroke-width="0.3"/>\n`;
226→
227→  const svg = `<?xml version="1.0" encoding="UTF-8"?>\n<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${pageW} ${pageH}" width="${pageW}mm" height="${pageH}mm">\n${svgContent}</svg>`;
228→
229→  return svg;
230→}
231→
232→export function downloadSketchSvg(project) {
233→  const svg = exportSketchSvg(project);
234→  if (!svg) return;
235→
236→  const blob = new Blob([svg], { type: 'image/svg+xml' });
237→  const url = URL.createObjectURL(blob);
238→  const a = document.createElement('a');
239→  a.href = url;
240→  a.download = `${project.name || 'sketch'}-sheet.svg`;
241→  document.body.appendChild(a);
242→  a.click();
243→  document.body.removeChild(a);
244→  URL.revokeObjectURL(url);
245→}
