  1→import { getPartExtents } from './viewProjection';
  2→
  3→function getAnchorPosition(part, anchor) {
  4→  const ext = getPartExtents(part);
  5→  const pos = part.position;
  6→
  7→  switch (anchor) {
  8→    case 'top': return pos.z + ext.height;
  9→    case 'bottom': return pos.z;
 10→    case 'left': return pos.x;
 11→    case 'right': return pos.x + ext.width;
 12→    case 'front': return pos.y;
 13→    case 'back': return pos.y + ext.depth;
 14→    case 'center': return null; // handled per-type
 15→    default: return 0;
 16→  }
 17→}
 18→
 19→function getAnchorAxis(anchor) {
 20→  switch (anchor) {
 21→    case 'top':
 22→    case 'bottom':
 23→      return 'z';
 24→    case 'left':
 25→    case 'right':
 26→      return 'x';
 27→    case 'front':
 28→    case 'back':
 29→      return 'y';
 30→    case 'center':
 31→      return null;
 32→    default:
 33→      return null;
 34→  }
 35→}
 36→
 37→function getAnchorExtentSize(part, anchor) {
 38→  const ext = getPartExtents(part);
 39→  switch (anchor) {
 40→    case 'top':
 41→    case 'bottom':
 42→      return ext.height;
 43→    case 'left':
 44→    case 'right':
 45→      return ext.width;
 46→    case 'front':
 47→    case 'back':
 48→      return ext.depth;
 49→    default:
 50→      return 0;
 51→  }
 52→}
 53→
 54→export function resolveConstraints(constraints, parts) {
 55→  const positions = new Map();
 56→  const partsById = new Map(parts.map((p) => [p.id, p]));
 57→
 58→  for (const constraint of constraints) {
 59→    const source = partsById.get(constraint.sourcePartId);
 60→    const target = partsById.get(constraint.targetPartId);
 61→    if (!source || !target) continue;
 62→
 63→    // Use already-resolved position if available
 64→    const sourcePos = { ...source.position, ...(positions.get(source.id) || {}) };
 65→    const targetPos = { ...target.position, ...(positions.get(target.id) || {}) };
 66→
 67→    const workingSource = { ...source, position: sourcePos };
 68→    const workingTarget = { ...target, position: targetPos };
 69→
 70→    const newPos = { ...sourcePos };
 71→
 72→    switch (constraint.type) {
 73→      case 'attach_face': {
 74→        const axis = getAnchorAxis(constraint.targetAnchor);
 75→        if (!axis) break;
 76→        const targetAnchorVal = getAnchorPosition(workingTarget, constraint.targetAnchor);
 77→        const sourceExtent = getAnchorExtentSize(workingSource, constraint.sourceAnchor);
 78→
 79→        // Position source so its sourceAnchor face touches target's targetAnchor face
 80→        if (constraint.sourceAnchor === 'bottom' || constraint.sourceAnchor === 'left' || constraint.sourceAnchor === 'front') {
 81→          newPos[axis] = targetAnchorVal + constraint.offset;
 82→        } else {
 83→          newPos[axis] = targetAnchorVal - sourceExtent + constraint.offset;
 84→        }
 85→        break;
 86→      }
 87→
 88→      case 'flush_surface': {
 89→        const axis = getAnchorAxis(constraint.targetAnchor);
 90→        if (!axis) break;
 91→        const targetAnchorVal = getAnchorPosition(workingTarget, constraint.targetAnchor);
 92→        const sourceExtent = getAnchorExtentSize(workingSource, constraint.sourceAnchor);
 93→
 94→        if (constraint.sourceAnchor === 'bottom' || constraint.sourceAnchor === 'left' || constraint.sourceAnchor === 'front') {
 95→          newPos[axis] = targetAnchorVal;
 96→        } else {
 97→          newPos[axis] = targetAnchorVal - sourceExtent;
 98→        }
 99→        break;
100→      }
101→
102→      case 'align_edge': {
103→        const axis = getAnchorAxis(constraint.targetAnchor);
104→        if (!axis) break;
105→        const targetVal = getAnchorPosition(workingTarget, constraint.targetAnchor);
106→        const sourceVal = getAnchorPosition(workingSource, constraint.sourceAnchor);
107→        newPos[axis] = sourcePos[axis] + (targetVal - sourceVal) + constraint.offset;
108→        break;
109→      }
110→
111→      case 'center_axis': {
112→        const targetExt = getPartExtents(workingTarget);
113→        const sourceExt = getPartExtents(workingSource);
114→        // Center source on target along X
115→        newPos.x = targetPos.x + (targetExt.width - sourceExt.width) / 2;
116→        // Center along Y
117→        newPos.y = targetPos.y + (targetExt.depth - sourceExt.depth) / 2;
118→        break;
119→      }
120→
121→      case 'inset_edge': {
122→        const axis = getAnchorAxis(constraint.targetAnchor);
123→        if (!axis) break;
124→        const targetExt = getPartExtents(workingTarget);
125→        const sourceExt = getPartExtents(workingSource);
126→        const inset = constraint.offset || 0;
127→
128→        if (constraint.targetAnchor === 'right' || constraint.targetAnchor === 'top' || constraint.targetAnchor === 'back') {
129→          const axisSize = axis === 'x' ? targetExt.width : axis === 'y' ? targetExt.depth : targetExt.height;
130→          const sourceSize = axis === 'x' ? sourceExt.width : axis === 'y' ? sourceExt.depth : sourceExt.height;
131→          newPos[axis] = targetPos[axis] + axisSize - sourceSize - inset;
132→        } else {
133→          newPos[axis] = targetPos[axis] + inset;
134→        }
135→        break;
136→      }
137→    }
138→
139→    positions.set(source.id, newPos);
140→  }
141→
142→  return positions;
143→}
