245→function ConstraintsSection({ part, project, dispatch }) {
246→  const [showForm, setShowForm] = useState(false);
247→  const [cType, setCType] = useState('attach_face');
248→  const [targetId, setTargetId] = useState('');
249→  const [srcAnchor, setSrcAnchor] = useState('bottom');
250→  const [tgtAnchor, setTgtAnchor] = useState('top');
251→  const [offset, setOffset] = useState(0);
252→
253→  const constraints = (project.constraints || []).filter(
254→    (c) => c.sourcePartId === part.id || c.targetPartId === part.id
255→  );
256→
257→  const otherParts = project.parts.filter((p) => p.id !== part.id && p.type !== 'dimension');
258→
259→  const handleAddConstraint = () => {
260→    if (!targetId) return;
261→    const constraint = createConstraint({
262→      type: cType,
263→      sourcePartId: part.id,
264→      targetPartId: targetId,
265→      sourceAnchor: srcAnchor,
266→      targetAnchor: tgtAnchor,
267→      offset: parseFloat(offset) || 0,
268→    });
269→    dispatch({ type: 'CONSTRAINT_ADD', constraint });
270→    setShowForm(false);
271→    setTargetId('');
272→  };
273→
274→  return (
275→    <div className={styles.fieldGroup}>
276→      <span className={styles.groupTitle}>Constraints</span>
277→      <div className={styles.constraintSection}>
278→        {constraints.map((c) => {
279→          const targetPart = project.parts.find((p) => p.id === (c.sourcePartId === part.id ? c.targetPartId : c.sourcePartId));
280→          return (
281→            <div key={c.id} className={styles.constraintItem}>
282→              <span>{c.type}: {c.sourceAnchor} → {c.targetAnchor} ({targetPart?.name || '?'})</span>
283→              <button
284→                className={styles.constraintDelete}
285→                onClick={() => dispatch({ type: 'CONSTRAINT_DELETE', constraintId: c.id })}
286→                title="Remove constraint"
287→              >
288→                ×
289→              </button>
290→            </div>
291→          );
292→        })}
293→      </div>
294→
295→      {!showForm ? (
296→        <button className={styles.duplicateBtn} onClick={() => setShowForm(true)}>
297→          Add Constraint
298→        </button>
299→      ) : (
300→        <div className={styles.constraintSection}>
301→          <SelectInput label="Type" value={cType} options={CONSTRAINT_TYPES} onChange={setCType} />
302→          <label className={styles.field}>
303→            <span className={styles.fieldLabel}>Target</span>
304→            <select className={styles.selectInput} value={targetId} onChange={(e) => setTargetId(e.target.value)}>
305→              <option value="">Select...</option>
306→              {otherParts.map((p) => (
307→                <option key={p.id} value={p.id}>{p.name} ({p.type})</option>
308→              ))}
309→            </select>
310→          </label>
311→          <SelectInput label="Source Anchor" value={srcAnchor} options={ANCHOR_OPTIONS} onChange={setSrcAnchor} />
312→          <SelectInput label="Target Anchor" value={tgtAnchor} options={ANCHOR_OPTIONS} onChange={setTgtAnchor} />
313→          <NumberInput label="Offset" value={offset} suffix="mm" onChange={setOffset} />
314→          <div style={{ display: 'flex', gap: '4px' }}>
315→            <button className={styles.duplicateBtn} onClick={handleAddConstraint}>Create</button>
316→            <button className={styles.duplicateBtn} onClick={() => setShowForm(false)}>Cancel</button>
317→          </div>
318→        </div>
319→      )}
320→    </div>
321→  );
322→}
