201→function BindDimensionUI({ parts, bindableProps, onBind }) {
202→  const [selectedPartId, setSelectedPartId] = useState('');
203→  const [selectedProp, setSelectedProp] = useState('');
204→
205→  const selectedPart = parts.find((p) => p.id === selectedPartId);
