448→export default function SketchPropertiesPanel() {
449→  const { getPart, dispatch, project } = useSketch();
450→  const { selectedId, selectedType, workspaceMode, activeSheetId, dispatch: editorDispatch } = useSketchEditor();
451→
452→  const isSheetMode = workspaceMode === 'sheet';
453→  const activeSheet = isSheetMode
454→    ? (project.sheets || []).find((s) => s.id === activeSheetId)
455→    : null;
456→
457→  // Sheet mode properties
458→  if (isSheetMode) {
459→    if (selectedType === 'sheetViewport' && selectedId && activeSheet) {
460→      const viewport = (activeSheet.viewports || []).find((vp) => vp.id === selectedId);
461→      if (viewport) {
462→        return (
463→          <div className={styles.panel}>
464→            <div className={styles.header}>Viewport Properties</div>
465→            <div className={styles.content}>
466→              <SheetViewportProperties
467→                viewport={viewport}
468→                sheet={activeSheet}
469→                project={project}
470→                dispatch={dispatch}
471→              />
472→            </div>
473→          </div>
474→        );
475→      }
476→    }
477→
478→    if (activeSheet) {
479→      const handleGenerateAssemblySheet = (assemblyId) => {
480→        const sheet = generateAssemblySheet(project, assemblyId);
481→        dispatch({ type: 'SKETCH_SHEET_ADD', sheet });
482→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
483→      };
484→
485→      const handleExportPdf = async () => {
486→        try {
487→          await exportActiveSheetAsPdf(activeSheet.title || 'sketch-sheet', activeSheet.paperSize);
488→        } catch (err) {
489→          console.error('PDF export failed:', err);
490→        }
491→      };
492→
493→      const handleExportPng = async () => {
494→        try {
495→          await exportActiveSheetAsPng(activeSheet.title || 'sketch-sheet');
496→        } catch (err) {
497→          console.error('PNG export failed:', err);
498→        }
499→      };
500→
501→      return (
502→        <div className={styles.panel}>
503→          <div className={styles.header}>Sheet Properties</div>
504→          <div className={styles.content}>
505→            <SheetProperties sheet={activeSheet} project={project} dispatch={dispatch} />
506→
507→            <div className={styles.fieldGroup}>
508→              <span className={styles.groupTitle}>Actions</span>
509→              {(project.assemblies || []).map((asm) => (
510→                <button
511→                  key={asm.id}
512→                  className={styles.duplicateBtn}
513→                  onClick={() => handleGenerateAssemblySheet(asm.id)}
514→                >
515→                  Generate Sheet: {asm.name}
516→                </button>
517→              ))}
518→              <button className={styles.duplicateBtn} onClick={handleExportPdf}>
519→                Export PDF
520→              </button>
521→              <button className={styles.duplicateBtn} onClick={handleExportPng}>
522→                Export PNG
523→              </button>
524→            </div>
525→          </div>
526→        </div>
527→      );
528→    }
529→
530→    return (
531→      <div className={styles.panel}>
532→        <div className={styles.header}>Properties</div>
533→        <div className={styles.empty}>No sheet selected</div>
534→      </div>
535→    );
536→  }
537→
538→  // Model mode properties
539→  const part = selectedId ? getPart(selectedId) : null;
540→
541→  if (!part) {
542→    return (
543→      <div className={styles.panel}>
544→        <div className={styles.header}>Properties</div>
545→        <div className={styles.empty}>Select a part to view its properties</div>
546→      </div>
547→    );
548→  }
549→
550→  const handleUpdate = (changes) => {
551→    dispatch({ type: 'PART_UPDATE', part: { id: part.id, ...changes } });
552→  };
553→
554→  const handlePositionUpdate = (posChanges) => {
555→    dispatch({ type: 'PART_UPDATE', part: { id: part.id, position: { ...part.position, ...posChanges } } });
556→  };
557→
558→  const handleDuplicate = () => {
559→    dispatch({ type: 'PART_CLONE', partId: part.id });
560→  };
561→
562→  const isDimension = part.type === 'dimension';
563→  const FieldsComponent = isDimension ? null : partFieldComponents[part.type];
564→
565→  // Find assembly this part belongs to
566→  const assembly = part.assemblyId
567→    ? project.assemblies.find((a) => a.id === part.assemblyId)
568→    : null;
569→
570→  return (
571→    <div className={styles.panel}>
572→      <div className={styles.header}>Properties</div>
573→
574→      <div className={styles.content}>
575→        {/* Name */}
576→        <TextInput label="Name" value={part.name} onChange={(v) => handleUpdate({ name: v })} />
577→
578→        {/* Type badge */}
579→        <div className={styles.field}>
580→          <span className={styles.fieldLabel}>Type</span>
581→          <span className={styles.typeBadge}>{part.type}</span>
582→        </div>
583→
584→        {/* Position (skip for dimensions) */}
585→        {!isDimension && (
586→          <PositionSection position={part.position} onUpdate={handlePositionUpdate} />
587→        )}
588→
589→        {/* Dimension-specific fields */}
590→        {isDimension && (
591→          <div className={styles.fieldGroup}>
592→            <span className={styles.groupTitle}>Dimension</span>
593→            <DimensionFields part={part} onUpdate={handleUpdate} dispatch={dispatch} project={project} />
594→          </div>
