596→
597→        {/* Type-specific dimensions */}
598→        {FieldsComponent && (
599→          <div className={styles.fieldGroup}>
600→            <span className={styles.groupTitle}>Dimensions</span>
601→            <FieldsComponent part={part} onUpdate={handleUpdate} />
602→          </div>
603→        )}
604→
605→        {/* Style (skip for dimensions) */}
606→        {!isDimension && (
607→          <div className={styles.fieldGroup}>
608→            <span className={styles.groupTitle}>Style</span>
609→            <label className={styles.field}>
610→              <span className={styles.fieldLabel}>Fill</span>
611→              <input
612→                type="color"
613→                value={part.fill === 'none' ? '#ffffff' : part.fill}
614→                onChange={(e) => handleUpdate({ fill: e.target.value })}
615→                className={styles.colorInput}
616→              />
617→            </label>
618→            <label className={styles.field}>
619→              <span className={styles.fieldLabel}>Stroke</span>
620→              <input
621→                type="color"
622→                value={part.stroke || '#1E2433'}
623→                onChange={(e) => handleUpdate({ stroke: e.target.value })}
624→                className={styles.colorInput}
625→              />
626→            </label>
627→          </div>
628→        )}
629→
630→        {/* Assembly (skip for dimensions) */}
631→        {!isDimension && (
632→          <div className={styles.fieldGroup}>
633→            <span className={styles.groupTitle}>Assembly</span>
